## Bug report

When I call `merge_config(base, overrides)` and then modify a nested dictionary in the returned config, the original `base` dictionary is also changed. The function should return an independent copy so that modifications don't affect the original base configuration.

### File: `config_merger.py`
```python
def merge_config(base: dict, overrides: dict) -> dict:
    """Merge override settings into a base configuration.

    Returns a new dictionary with base values updated by overrides.
    The returned config should be independent of the base.
    """
    result = base.copy()
    for key, value in overrides.items():
        if key in result and isinstance(result[key], dict) and isinstance(value, dict):
            result[key].update(value)
        else:
            result[key] = value
    return result
```

### File: `test_config_merger.py`
```python
from config_merger import merge_config

def test_simple_override():
    base = {"timeout": 30, "retries": 3}
    overrides = {"timeout": 60}
    result = merge_config(base, overrides)
    assert result == {"timeout": 60, "retries": 3}
    assert base == {"timeout": 30, "retries": 3}

def test_nested_merge():
    base = {"database": {"host": "localhost", "port": 5432}}
    overrides = {"database": {"port": 3306}}
    result = merge_config(base, overrides)
    assert result == {"database": {"host": "localhost", "port": 3306}}

def test_result_independent_from_base():
    base = {"server": {"host": "localhost", "port": 8000}}
    overrides = {"server": {"port": 9000}}
    result = merge_config(base, overrides)
    result["server"]["host"] = "example.com"
    assert base["server"]["host"] == "localhost"

def test_add_new_key():
    base = {"timeout": 30}
    overrides = {"retries": 5}
    result = merge_config(base, overrides)
    assert result == {"timeout": 30, "retries": 5}
```

